const { db } = require('../config/database');
const CacheService = require('../services/cacheService');

class Pixel {
  static tableName = 'pixels';

  /**
   * 创建或更新像素（统一使用pattern_id）
   */
  static async createOrUpdate(pixelData) {
    const { 
      gridId, 
      lat, 
      lng, 
      userId, 
      patternId, 
      patternAnchorX, 
      patternAnchorY, 
      patternRotation, 
      patternMirror 
    } = pixelData;
    
    try {
      // 检查是否已存在像素
      const existingPixel = await this.findByGridId(gridId);
      
      if (existingPixel) {
        // 更新现有像素
        const updateData = {
          user_id: userId,
          updated_at: db.fn.now()
        };

        // 统一使用图案ID
        updateData.pattern_id = patternId;
        updateData.pattern_anchor_x = patternAnchorX || 0;
        updateData.pattern_anchor_y = patternAnchorY || 0;
        updateData.pattern_rotation = patternRotation || 0;
        updateData.pattern_mirror = patternMirror || false;

        const [updatedPixel] = await db(this.tableName)
          .where({ grid_id: gridId })
          .update(updateData)
          .returning('*');
        
        // 清除缓存
        await CacheService.clearPixelCache(gridId);
        
        return updatedPixel;
      } else {
        // 创建新像素
        const insertData = {
          grid_id: gridId,
          latitude: lat,
          longitude: lng,
          user_id: userId,
          color: '#FF0000', // 添加默认颜色
        };

        // 统一使用图案ID
        insertData.pattern_id = patternId;
        insertData.pattern_anchor_x = patternAnchorX || 0;
        insertData.pattern_anchor_y = patternAnchorY || 0;
        insertData.pattern_rotation = patternRotation || 0;
        insertData.pattern_mirror = patternMirror || false;

        const [newPixel] = await db(this.tableName)
          .insert(insertData)
          .returning('*');
        
        return newPixel;
      }
    } catch (error) {
      console.error('创建或更新像素失败:', error);
      throw error;
    }
  }

  /**
   * 根据网格ID查找像素
   */
  static async findByGridId(gridId) {
    try {
      // 先从缓存获取
      const cachedPixel = await CacheService.getPixel(gridId);
      if (cachedPixel) {
        return cachedPixel;
      }
      
      // 从数据库获取
      const pixel = await db(this.tableName)
        .where({ grid_id: gridId })
        .first();
      
      // 缓存结果
      if (pixel) {
        await CacheService.setPixel(gridId, pixel);
      }
      
      return pixel;
    } catch (error) {
      console.error('查找像素失败:', error);
      throw error;
    }
  }

  /**
   * 批量查找像素
   */
  static async findByGridIds(gridIds) {
    try {
      const result = {};
      const uncachedGridIds = [];
      
      // 先从缓存获取
      for (const gridId of gridIds) {
        const cachedPixel = await CacheService.getPixel(gridId);
        if (cachedPixel) {
          result[gridId] = cachedPixel;
        } else {
          uncachedGridIds.push(gridId);
        }
      }
      
      // 从数据库获取未缓存的像素
      if (uncachedGridIds.length > 0) {
        const pixels = await db(this.tableName)
          .whereIn('grid_id', uncachedGridIds)
          .select('*');
        
        // 缓存并添加到结果
        for (const pixel of pixels) {
          result[pixel.grid_id] = pixel;
          await CacheService.setPixel(pixel.grid_id, pixel);
        }
      }
      
      return result;
    } catch (error) {
      console.error('批量查找像素失败:', error);
      throw error;
    }
  }



  /**
   * 删除像素
   */
  static async deleteByGridId(gridId) {
    try {
      const deletedCount = await db(this.tableName)
        .where({ grid_id: gridId })
        .del();
      
      // 清除缓存
      await CacheService.clearPixelCache(gridId);
      
      return deletedCount > 0;
    } catch (error) {
      console.error('删除像素失败:', error);
      throw error;
    }
  }

  /**
   * 获取用户的所有像素
   */
  static async getByUserId(userId, limit = 100, offset = 0) {
    try {
      return await db(this.tableName)
        .where({ user_id: userId })
        .orderBy('created_at', 'desc')
        .limit(limit)
        .offset(offset);
    } catch (error) {
      console.error('获取用户像素失败:', error);
      throw error;
    }
  }

  /**
   * 统计用户像素数量
   */
  static async countByUserId(userId) {
    try {
      const result = await db(this.tableName)
        .where({ user_id: userId })
        .count('* as count')
        .first();
      
      return parseInt(result.count);
    } catch (error) {
      console.error('统计用户像素失败:', error);
      throw error;
    }
  }

  /**
   * 获取区域内的像素
   */
  static async getByRegion(minLat, maxLat, minLng, maxLng) {
    try {
      return await db(this.tableName)
        .whereBetween('lat', [minLat, maxLat])
        .whereBetween('lng', [minLng, maxLng])
        .select('*');
    } catch (error) {
      console.error('获取区域像素失败:', error);
      throw error;
    }
  }

  /**
   * 批量删除像素
   */
  static async deleteByGridIds(gridIds) {
    try {
      const deletedCount = await db(this.tableName)
        .whereIn('grid_id', gridIds)
        .del();
      
      // 清除缓存
      for (const gridId of gridIds) {
        await CacheService.clearPixelCache(gridId);
      }
      
      return deletedCount;
    } catch (error) {
      console.error('批量删除像素失败:', error);
      throw error;
    }
  }
}

module.exports = Pixel;
